import type * as React from 'react';

import {cn} from '@/lib/utils';

import {ChevronDown, ChevronUp} from 'lucide-react';
import {Accordion as AccordionPrimitive} from 'radix-ui';

/**
 * A vertically stacked set of interactive headings that each reveal an associated section of content.
 *
 * ### Component Props
 *
 * See [Accordion props](https://www.radix-ui.com/primitives/docs/components/accordion) documentation for full details.
 *
 * | Prop                | Type                                  | Default      |
 * | :------------------ | :------------------------------------ | :----------- |
 * | _asChild_           | `boolean`                             | `false`      |
 * | _type_ *(required)* | `"single" \| "multiple"`              | -            |
 * | _value_             | `string \| string[]`                  | -            |
 * | _defaultValue_      | `string \| string[]`                  | -            |
 * | _onValueChange_     | `(value: string \| string[]) => void` | -            |
 * | _collapsible_       | `boolean`                             | `false`      |
 * | _disabled_          | `boolean`                             | `false`      |
 * | _dir_               | `"ltr" \| "rtl"`                      | `"ltr"`      |
 * | _orientation_       | `"vertical" \| "horizontal"`          | `"vertical"` |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <Accordion type="single" collapsible defaultValue="item-1">
 *   <AccordionItem value="item-1">
 *     <AccordionTrigger>Is it accessible?</AccordionTrigger>
 *     <AccordionContent>
 *       Yes. It adheres to the WAI-ARIA design pattern.
 *     </AccordionContent>
 *   </AccordionItem>
 * </Accordion>
 * ```
 *
 * ### Accessibility (WCAG 2.2 AA)
 *
 * @wcag 4.1.2 Name, Role, Value â€” headings, buttons, and regions via Radix Accordion primitives with `aria-expanded` state.
 * @wcag 2.1.1 Keyboard â€” triggers focusable and activated via Enter/Space; arrow keys navigate between items.
 * @wcag 2.4.7 Focus Visible â€” focus ring on triggers via `focus-visible:ring-3`.
 */
function Accordion({
  className,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Root>) {
  return (
    <AccordionPrimitive.Root
      data-slot="accordion"
      className={cn('flex w-full flex-col', className)}
      {...props}
    />
  );
}

/**
 * A single collapsible section within an Accordion.
 *
 * ### Component Props
 *
 * See [Accordion Item props](https://www.radix-ui.com/primitives/docs/components/accordion#item) documentation for full details.
 *
 * | Prop                 | Type      | Default |
 * | :------------------- | :-------- | :------ |
 * | _asChild_            | `boolean` | `false` |
 * | _value_ *(required)* | `string`  | -       |
 * | _disabled_           | `boolean` | `false` |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <AccordionItem value="item-1">
 *   <AccordionTrigger>Section heading</AccordionTrigger>
 *   <AccordionContent>Section content</AccordionContent>
 * </AccordionItem>
 * ```
 */
function AccordionItem({
  className,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Item>) {
  return (
    <AccordionPrimitive.Item
      data-slot="accordion-item"
      className={cn('not-last:border-b not-last:border-border', className)}
      {...props}
    />
  );
}

/**
 * The interactive heading that toggles the expanded state of its associated AccordionContent.
 *
 * ### Component Props
 *
 * See [Accordion Trigger props](https://www.radix-ui.com/primitives/docs/components/accordion#trigger) documentation for full details.
 *
 * | Prop      | Type      | Default |
 * | :-------- | :-------- | :------ |
 * | _asChild_ | `boolean` | `false` |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <AccordionTrigger>Is it accessible?</AccordionTrigger>
 * ```
 */
function AccordionTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Trigger>) {
  return (
    <AccordionPrimitive.Header className="flex">
      <AccordionPrimitive.Trigger
        data-slot="accordion-trigger"
        className={cn(
          'group/accordion-trigger relative flex flex-1 items-start justify-between rounded border border-transparent py-4 text-left text-sm font-label tracking-label transition-all ease-default outline-none hover:underline focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring focus-visible:after:border-ring disabled:pointer-events-none disabled:opacity-50 **:data-[slot=accordion-trigger-icon]:ml-auto **:data-[slot=accordion-trigger-icon]:size-4 **:data-[slot=accordion-trigger-icon]:text-muted-foreground',
          className
        )}
        {...props}
      >
        {children}
        <ChevronDown
          data-slot="accordion-trigger-icon"
          className="pointer-events-none shrink-0 group-aria-expanded/accordion-trigger:hidden"
        />
        <ChevronUp
          data-slot="accordion-trigger-icon"
          className="pointer-events-none hidden shrink-0 group-aria-expanded/accordion-trigger:inline"
        />
      </AccordionPrimitive.Trigger>
    </AccordionPrimitive.Header>
  );
}

/**
 * The collapsible content panel that is revealed when its associated AccordionTrigger is activated.
 *
 * ### Component Props
 *
 * See [Accordion Content props](https://www.radix-ui.com/primitives/docs/components/accordion#content) documentation for full details.
 *
 * | Prop         | Type      | Default |
 * | :----------- | :-------- | :------ |
 * | _asChild_    | `boolean` | `false` |
 * | _forceMount_ | `boolean` | -       |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <AccordionContent>
 *   Yes. It adheres to the WAI-ARIA design pattern.
 * </AccordionContent>
 * ```
 */
function AccordionContent({
  className,
  children,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Content>) {
  return (
    <AccordionPrimitive.Content
      data-slot="accordion-content"
      className="overflow-hidden text-sm data-open:animate-accordion-down data-closed:animate-accordion-up"
      {...props}
    >
      <div
        className={cn(
          'h-(--radix-accordion-content-height) pt-0 pb-4 [&_a]:underline [&_a]:underline-offset-3 [&_a]:hover:text-foreground [&_p:not(:last-child)]:mb-4',
          className
        )}
      >
        {children}
      </div>
    </AccordionPrimitive.Content>
  );
}

export {Accordion, AccordionItem, AccordionTrigger, AccordionContent};
